"use client";

import { Badge } from "@/components/ui/badge";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { ScrollArea } from "@/components/ui/scroll-area";
import { cn } from "@/lib/utils";
import type { EvidenceFile, TimelineEvent } from "@/types/claim";

interface TimelinePanelProps {
  events: TimelineEvent[];
  evidenceFiles: EvidenceFile[];
  selectedEventId: string;
  onSelectEvent: (id: string) => void;
}

export function TimelinePanel({
  events,
  evidenceFiles,
  selectedEventId,
  onSelectEvent,
}: TimelinePanelProps) {
  return (
    <aside className="flex min-h-[24rem] flex-col border-t border-border bg-white xl:min-h-0 xl:border-t-0">
      <div className="border-b border-border px-4 py-4">
        <h2 className="text-sm font-semibold text-slate-900">Event Timeline</h2>
        <p className="mt-1 text-xs text-muted-foreground">
          Click an event to synchronize the investigation view
        </p>
      </div>

      <ScrollArea className="flex-1">
        <div className="relative px-4 py-4">
          <div className="absolute top-4 bottom-4 left-[23px] w-px bg-slate-200" />
          <div className="space-y-3">
            {events.map((event) => {
              const isSelected = event.id === selectedEventId;
              const linkedFiles = event.linkedEvidenceIds
                .map((id) => evidenceFiles.find((file) => file.id === id))
                .filter(Boolean) as EvidenceFile[];

              return (
                <button
                  key={event.id}
                  type="button"
                  onClick={() => onSelectEvent(event.id)}
                  className={cn(
                    "relative w-full rounded-lg border p-3 text-left transition-all",
                    isSelected
                      ? "border-slate-400 bg-slate-50 shadow-sm"
                      : "border-slate-200 bg-white hover:border-slate-300 hover:bg-slate-50/80"
                  )}
                >
                  <div
                    className={cn(
                      "absolute top-4 -left-[9px] size-3 rounded-full border-2 border-white",
                      isSelected ? "bg-amber-500" : "bg-slate-300"
                    )}
                  />
                  <div className="pl-2">
                    <p className="font-mono text-xs text-slate-500">
                      {event.timestamp}
                    </p>
                    <p className="mt-1 text-sm font-semibold text-slate-900">
                      {event.title}
                    </p>
                    <p className="mt-1 text-xs leading-relaxed text-slate-600">
                      {event.description}
                    </p>
                    <div className="mt-2 flex flex-wrap gap-1.5">
                      {linkedFiles.map((file) => (
                        <Badge
                          key={file.id}
                          variant="outline"
                          className="h-5 bg-white text-[10px] font-normal"
                        >
                          {file.name}
                        </Badge>
                      ))}
                    </div>
                  </div>
                </button>
              );
            })}
          </div>
        </div>
      </ScrollArea>
    </aside>
  );
}
